class Image extends React.Component {
  render() {
    const { src, alt, title, variant, backGround = "" } = this.props;
    return (
      <div className={"image-container " + (backGround ? "background-color" : "")}>
        <h2>{title}</h2>
        <img
          src={src}
          alt={alt}
          className={`image ${variant === "circle" ? "circle" : "square"}`}
        />
      </div>
    );
  }
}

export default Image;
